1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface Step {
8	  type: string;
9	  items: Item[];
10	}
11	
12	interface Customer {
13	  yearsWithMHPCO: number;
14	}
15	
16	interface Scenario {
17	  customer: Customer;
18	  steps: Step[];
19	}
20	
21	const PROCESSING_FEE = 5;
22	const FIRST_INSURANCE_RATE = 0.1;
23	
24	const BASE_PREMIUM: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	
33	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
34	const BLOCK_SIZE = 3;
35	const BLOCK_PREMIUM = 60;
36	const CURSE_SURCHARGE_RATE = 0.5;
37	const HIGH_ENCHANTMENT_THRESHOLD = 5;
38	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
39	const LOYALTY_THRESHOLD_YEARS = 2;
40	const LOYALTY_DISCOUNT_RATE = 0.2;
41	
42	function calculateBasePremium(items: Item[]): number {
43	  const typeCounts: Record<string, number> = {};
44	  for (const item of items) {
45	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
46	  }
47	
48	  return Object.entries(typeCounts).reduce((total, [type, count]) => {
49	    const premium = COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
50	      ? BLOCK_PREMIUM
51	      : count * BASE_PREMIUM[type];
52	    return total + premium;
53	  }, 0);
54	}
55	
56	function calculateLoyaltyDiscount(customer: Customer, basePremium: number): number {
57	  return customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
58	    ? basePremium * LOYALTY_DISCOUNT_RATE
59	    : 0;
60	}
61	
62	function calculateItemSurcharges(items: Item[]): number {
63	  return items.reduce((total, item) => {
64	    const itemBasePremium = BASE_PREMIUM[item.type];
65	    const curseSurcharge = item.cursed ? itemBasePremium * CURSE_SURCHARGE_RATE : 0;
66	    const enchantmentSurcharge = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
67	      ? itemBasePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE
68	      : 0;
69	    return total + curseSurcharge + enchantmentSurcharge;
70	  }, 0);
71	}
72	
73	export function processScenario(scenario: Scenario): unknown {
74	  const items = scenario.steps[0].items;
75	  const basePremium = calculateBasePremium(items);
76	  const itemSurcharges = calculateItemSurcharges(items);
77	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
78	  const loyaltyDiscount = calculateLoyaltyDiscount(scenario.customer, basePremium);
79	  const premium = Math.ceil(basePremium + itemSurcharges + firstInsurance - loyaltyDiscount + PROCESSING_FEE);
80	
81	  return [{ premium }];
82	}
